from cryptography.hazmat.primitives.asymmetric import rsa, padding
from cryptography.hazmat.primitives import hashes

def generate_rsa_keypair(key_size: int = 2048):
    private_key = rsa.generate_private_key(
        public_exponent=65537,
        key_size=key_size
    )
    return private_key, private_key.public_key()

def sign_message(private_key, message: bytes) -> bytes:
    signature = private_key.sign(
        message,
        padding.PSS(
            mgf=padding.MGF1(hashes.SHA256()),
            salt_length=padding.PSS.MAX_LENGTH
        ),
        hashes.SHA256()
    )
    return signature

def verify_signature(public_key, message: bytes, signature: bytes) -> bool:
    try:
        public_key.verify(
            signature,
            message,
            padding.PSS(
                mgf=padding.MGF1(hashes.SHA256()),
                salt_length=padding.PSS.MAX_LENGTH
            ),
            hashes.SHA256()
        )
        return True
    except Exception:
        return False

from cryptography.hazmat.primitives.asymmetric import ed25519

class Ed25519Signer:
    def __init__(self):
        self.private_key = ed25519.Ed25519PrivateKey.generate()
        self.public_key = self.private_key.public_key()

    def sign(self, message: bytes) -> bytes:
        return self.private_key.sign(message)

    def verify(self, message: bytes, signature: bytes) -> bool:
        try:
            self.public_key.verify(signature, message)
            return True
        except Exception:
            return False

    def is_deterministic(self, message: bytes) -> bool:
        sig1 = self.sign(message)
        sig2 = self.sign(message)
        return sig1 == sig2

from cryptography.hazmat.primitives.asymmetric import rsa, ec, ed25519, padding
from cryptography.hazmat.primitives import hashes, serialization
import time

def measure_signature_sizes() -> dict:
    message = b"Test message for signature comparison"

    # RSA-2048
    rsa_key = rsa.generate_private_key(65537, 2048)
    rsa_sig = rsa_key.sign(message, padding.PSS(
        mgf=padding.MGF1(hashes.SHA256()),
        salt_length=padding.PSS.MAX_LENGTH
    ), hashes.SHA256())

    # ECDSA P-256
    ec_key = ec.generate_private_key(ec.SECP256R1())
    ec_sig = ec_key.sign(message, ec.ECDSA(hashes.SHA256()))

    # Ed25519
    ed_key = ed25519.Ed25519PrivateKey.generate()
    ed_sig = ed_key.sign(message)

    return {
        'RSA-2048': len(rsa_sig),
        'ECDSA-P256': len(ec_sig),
        'Ed25519': len(ed_sig)
    }

def measure_public_key_sizes() -> dict:
    rsa_key = rsa.generate_private_key(65537, 2048)
    ec_key = ec.generate_private_key(ec.SECP256R1())
    ed_key = ed25519.Ed25519PrivateKey.generate()

    def get_pubkey_size(key):
        return len(key.public_key().public_bytes(
            encoding=serialization.Encoding.DER,
            format=serialization.PublicFormat.SubjectPublicKeyInfo
        ))

    return {
        'RSA-2048': get_pubkey_size(rsa_key),
        'ECDSA-P256': get_pubkey_size(ec_key),
        'Ed25519': get_pubkey_size(ed_key)
    }

def compare_schemes() -> dict:
    return {
        'signature_sizes': measure_signature_sizes(),
        'public_key_sizes': measure_public_key_sizes()
    }

from cryptography.hazmat.primitives.asymmetric import ed25519
from cryptography.hazmat.primitives import serialization
import hashlib
import json
import base64
from datetime import datetime

class DocumentSigner:
    def __init__(self):
        self.private_key = ed25519.Ed25519PrivateKey.generate()
        self.public_key = self.private_key.public_key()

    def sign_document(self, document: bytes, metadata: dict = None) -> dict:
        # Hash the document
        doc_hash = hashlib.sha256(document).hexdigest()

        # Sign the hash
        signature = self.private_key.sign(doc_hash.encode())

        # Get public key bytes
        pub_bytes = self.public_key.public_bytes(
            encoding=serialization.Encoding.Raw,
            format=serialization.PublicFormat.Raw
        )

        return {
            'document_hash': doc_hash,
            'signature': base64.b64encode(signature).decode(),
            'public_key': base64.b64encode(pub_bytes).decode(),
            'timestamp': datetime.utcnow().isoformat(),
            'algorithm': 'Ed25519',
            'metadata': metadata or {}
        }

    def verify_document(self, document: bytes, signature_package: dict) -> dict:
        try:
            # Verify hash matches
            doc_hash = hashlib.sha256(document).hexdigest()
            if doc_hash != signature_package['document_hash']:
                return {'valid': False, 'message': 'Document hash mismatch', 'details': {}}

            # Load public key
            pub_bytes = base64.b64decode(signature_package['public_key'])
            public_key = ed25519.Ed25519PublicKey.from_public_bytes(pub_bytes)

            # Verify signature
            signature = base64.b64decode(signature_package['signature'])
            public_key.verify(signature, doc_hash.encode())

            return {
                'valid': True,
                'message': 'Signature is valid',
                'details': {
                    'signed_at': signature_package.get('timestamp'),
                    'algorithm': signature_package.get('algorithm')
                }
            }
        except Exception as e:
            return {'valid': False, 'message': f'Verification failed: {str(e)}', 'details': {}}
